INSERT INTO system_templates (template_key, name, subject, content, variables_description) VALUES
('email.accountability.submitted', 'Prestação de Contas Enviada', 'Nova Prestação de Contas - {{programa}}', '<p>Olá,</p><p>Uma nova prestação de contas foi enviada e aguarda análise.</p><p><strong>Competência:</strong> {{competencia}}</p><p><strong>Programa:</strong> {{programa}}</p><p>Acesse o sistema para analisar.</p>', '{{competencia}} = Mês/Ano da Prestação\n{{programa}} = Nome do Programa'),

('email.accountability.approved', 'Prestação de Contas Aprovada', 'Prestação de Contas Aprovada - {{programa}}', '<p>Olá {{nome}},</p><p>Boas notícias! A prestação de contas de <strong>{{competencia}}</strong> do programa <strong>{{programa}}</strong> foi aprovada.</p><p>Acesse o Portal da Entidade no SIGTEF para ver os detalhes.</p>', '{{nome}} = Nome do Representante\n{{competencia}} = Mês/Ano da Prestação\n{{programa}} = Nome do Programa'),

('email.issue.created', 'Nova Pendência na Prestação de Contas', 'Nova Pendência - SIGTEF', '<p>Olá {{nome}},</p><p>Uma nova pendência do tipo <strong>{{tipo_pendencia}}</strong> foi registrada em sua prestação de contas.</p><p><strong>Detalhes:</strong> {{detalhes}}</p><p>Acesse o Portal da Entidade no SIGTEF para resolver a pendência e não travar o andamento da prestação.</p>', '{{nome}} = Nome do Representante\n{{tipo_pendencia}} = Tipo da Pendência\n{{detalhes}} = Descrição da Pendência');
